304:         <div class="input-group">
305:             <input 
306:                 type="text" 
307:                 id="todoInput" 
308:                 placeholder="What needs to be done?"
309:                 autocomplete="off"
310:             >
311:             <button class="add-btn" onclick="addTodo()">Add</button>
312:         </div>
313: 
314:         <ul class="todo-list" id="todoList"></ul>
315:         
316:         <div id="emptyState" class="empty-state">
317:             <div class="empty-state-icon">📭</div>
318:             <div>No tasks yet. Create one to get started!</div>
319:         </div>
320: 
321:         <div class="stats">
322:             <div class="stat">
323:                 <span class="stat-number" id="totalCount">0</span>
324:                 <span class="stat-label">Total</span>
325:             </div>
326:             <div class="stat">
327:                 <span class="stat-number" id="completedCount">0</span>
328:                 <span class="stat-label">Done</span>
329:             </div>
330:             <div class="stat">
331:                 <span class="stat-number" id="pendingCount">0</span>
332:                 <span class="stat-label">Pending</span>
333:             </div>
334:         </div>
335:     </div>
