337:     <script>
338:         const todoInput = document.getElementById('todoInput');
339:         const todoList = document.getElementById('todoList');
340:         const emptyState = document.getElementById('emptyState');
341:         const themeToggle = document.getElementById('themeToggle');
342: 
343:         // Load todos and theme from localStorage
344:         let todos = JSON.parse(localStorage.getItem('todos')) || [];
345:         const isDarkMode = localStorage.getItem('darkMode') === 'true';
346: 
347:         // Initialize theme
348:         if (isDarkMode) {
349:             document.body.classList.add('dark-mode');
350:             themeToggle.textContent = '☀️';
351:         }
352: 
353:         // Theme toggle
354:         themeToggle.addEventListener('click', () => {
355:             document.body.classList.toggle('dark-mode');
356:             const newDarkMode = document.body.classList.contains('dark-mode');
357:             localStorage.setItem('darkMode', newDarkMode);
358:             themeToggle.textContent = newDarkMode ? '☀️' : '🌙';
359:         });
360: 
361:         // Render todos on page load
362:         renderTodos();
363: 
364:         // Add todo on Enter key
365:         todoInput.addEventListener('keypress', (e) => {
366:             if (e.key === 'Enter') {
367:                 addTodo();
368:             }
369:         });
370: 
371:         function addTodo() {
372:             const text = todoInput.value.trim();
373:             
374:             if (!text) {
375:                 alert('Please enter a task');
376:                 return;
377:             }
378: 
379:             const todo = {
380:                 id: Date.now(),
381:                 text: text,
382:                 completed: false
383:             };
384: 
385:             todos.push(todo);
386:             saveTodos();
387:             renderTodos();
388:             todoInput.value = '';
389:             todoInput.focus();
390:         }
391: 
392:         function deleteTodo(id) {
393:             todos = todos.filter(todo => todo.id !== id);
394:             saveTodos();
395:             renderTodos();
396:         }
397: 
398:         function toggleTodo(id) {
399:             const todo = todos.find(t => t.id === id);
400:             if (todo) {
401:                 todo.completed = !todo.completed;
402:                 saveTodos();
403:                 renderTodos();
404:             }
405:         }
406: 
407:         function renderTodos() {
408:             todoList.innerHTML = '';
409: 
410:             if (todos.length === 0) {
411:                 emptyState.style.display = 'block';
412:                 updateStats();
413:                 return;
414:             }
415: 
416:             emptyState.style.display = 'none';
417: 
418:             todos.forEach(todo => {
419:                 const li = document.createElement('li');
420:                 li.className = `todo-item ${todo.completed ? 'completed' : ''}`;
421:                 
422:                 li.innerHTML = `
423:                     <input 
424:                         type="checkbox" 
425:                         ${todo.completed ? 'checked' : ''}
426:                         onchange="toggleTodo(${todo.id})"
427:                     >
428:                     <span class="todo-text">${escapeHtml(todo.text)}</span>
429:                     <button class="delete-btn" onclick="deleteTodo(${todo.id})">Delete</button>
430:                 `;
431:                 
432:                 todoList.appendChild(li);
433:             });
434: 
435:             updateStats();
436:         }
437: 
438:         function updateStats() {
439:             const total = todos.length;
440:             const completed = todos.filter(t => t.completed).length;
441:             const pending = total - completed;
442: 
443:             document.getElementById('totalCount').textContent = total;
444:             document.getElementById('completedCount').textContent = completed;
445:             document.getElementById('pendingCount').textContent = pending;
446:         }
447: 
448:         function saveTodos() {
449:             localStorage.setItem('todos', JSON.stringify(todos));
450:         }
451: 
452:         function escapeHtml(text) {
453:             const div = document.createElement('div');
454:             div.textContent = text;
455:             return div.innerHTML;
456:         }
457:     </script>
458: </body>
